pub struct RiscV64;

unsafe impl Arch for RiscV64 {
    const INIT_EXEC_PATH: &ByteStr = ByteStr::from_bytes(b"/rv-init");

    type Regs = regs::Regs;
    type Basic = basic::Basic;
    type Chrono = chrono::Chrono;
    type UAccessRaw = uaccess_raw::UAccessRaw;
    type Trap = trap::Trap;

    #[unsafe(no_mangle)]
    #[naked]
    #[unsafe(link_section = ".text.entry")]
    extern "C" fn _start() {
        unsafe {
            naked_asm!(
                // 此时，尽管程序认为自己位于高 256 GB 处，实际它还是被加载到了正常入口点位置，因此必须先启用虚拟内存
                // === 注意 ===
                // 这里按理来说是要手动偏移的（因为 BOOT_PAGE_TABLE 位于一个很高的虚拟地址），但是 Rust 编译器会在所
                // 有优化等级下将其编译为依据 pc 间接寻址，而 Rust 编译器认为的 pc 恰好也是虚拟地址，二者的相对偏移量相同，
                // 因此 t1 可以直接加载到 BOOT_PAGE_TABLE 的实际物理地址。
                // 它只是恰好能工作！
                // ============
                // "li t0, {LINEAR_MAPPING_OFFSET}",
                "la t1, {BOOT_PAGE_TABLE}",
                // "sub t1, t1, t0",
                "li t2, 8 << 60",
                "srli t1, t1, 12",
                "or t1, t1, t2",
                "csrw satp, t1",
                "sfence.vma",
                // 现在虚拟地址已经启用，不过 PC 还在低地址，这会让一些相对寻址失效。
                // 目前不会出问题，因为我们也映射了低地址，但长远考虑这里还是要挪 PC。
                // 注意即使是内核也没办法直接改 PC，我们只能用跳转指令操作。
                "li t0, {LINEAR_MAPPING_OFFSET} + 4 * 2", // 注意这个偏移量和下面的汇编代码长度强相关！（是的这代码很烂）
                "auipc t1, 0",
                "add t1, t1, t0",
                "jr t1",
                // OK，现在一切正常了！
                "la sp, boot_stack_top",
                "call {main}", // j 在调试模式下会因为跳转距离过远而失败
                BOOT_PAGE_TABLE = sym BOOT_PAGE_TABLE,
                LINEAR_MAPPING_OFFSET = const LINEAR_MAPPING_OFFSET,
                main = sym main,
            );
        }
    }
}

#[repr(align(4096))]
#[allow(dead_code)] // 尽管 Rust 侧不会读取其成员，汇编侧会访问它，因此并非“死代码”
struct BootPageTable([usize; 512]);

static BOOT_PAGE_TABLE: BootPageTable = const {
    let mut entries = [0; 512];

    const VX: usize = PTEFlagsNative::Valid.bits() | PTEFlagsNative::Execute.bits();
    const VRWX: usize = VX | PTEFlagsNative::Read.bits() | PTEFlagsNative::Write.bits();

    // 将低地址的 0x80000000~... 和高地址的都映射到同一个位置
    // 这是因为 Rust 编译器认为自己位于高地址，因此各种全局变量都会从高地址拿数据
    // 但程序实际跑在低地址，特别是刚启动时，直接使用的就是物理地址。为了 pc 还能用，必须暂时映射低地址。
    entries[2] = PhysPageNum::<2>(2).mask() | VX;
    entries[256 + 2] = PhysPageNum::<2>(2).mask() | VRWX;

    // 然后，由于 VirtIO 设备普遍使用 0x10000000 附近的地址，我们将这部分也进行映射
    entries[256 + 0] = PhysPageNum::<2>(0).mask() | VRWX;

    BootPageTable(entries)
};

use core::arch::asm;

use crate::arch::interfaces;

pub struct Regs;

unsafe impl interfaces::Regs for Regs {
    fn get_fp() -> Self::RegType {
        let fp;
        unsafe { asm!("mv {0}, s0", out(reg) fp, options(nostack, nomem, preserves_flags)) };
        fp
    }

    fn get_tp() -> Self::RegType {
        let tp;
        unsafe { asm!("mv {0}, tp", out(reg) tp, options(nostack, nomem, preserves_flags)) };
        tp
    }
    fn set_tp(tp: Self::RegType) {
        unsafe { asm!("mv tp, {0}", in(reg) tp, options(nostack, nomem, preserves_flags)) };
    }

    fn get_sp() -> Self::RegType {
        let sp;
        unsafe { asm!("mv {0}, sp", out(reg) sp, options(nostack, nomem, preserves_flags)) };
        sp
    }

    fn set_trap_handler(new_handler: extern "C" fn()) {
        unsafe {
            asm!("csrw stvec, {0}", in(reg) new_handler, options(nostack, nomem, preserves_flags))
        };
    }
}

use core::{
    arch::{asm, naked_asm},
    mem::{offset_of, transmute},
};

use bit_field::BitField;
use derive_more::Debug;
use seq_macro::seq;

use crate::{arch::interfaces, trap::trap_handler::recover_task_pointer};

pub struct Trap;

unsafe impl interfaces::Trap for Trap {
    type TrapContext = TrapContext;

    #[repr(align(4))]
    #[naked]
    #[unsafe(no_mangle)]
    extern "C" fn trap_handler_raw_from_user() {
        unsafe {
            seq!(N in 3..=31 {
                naked_asm!(
                    // 1. 切换到内核栈
                    "csrrw sp, sscratch, sp",
                    // 2. 为 TrapContext 留出栈空间
                    "addi sp, sp, -{TRAP_CONTEXT_SIZE}",
                    // 3. 保存寄存器（x1 ~ x31，不含 x2 (sp)——它现在存放的是内核栈的地址）
                    "sd x1, {REGS_OFFSET}(sp)",
                    #(
                        concat!("sd x", N, ", (", N, "-1)*8+{REGS_OFFSET}(sp)"),
                    )*
                    // 4. 保存 sstatus 和 sepc
                    "csrr a0, sstatus",
                    "sd a0, {STATUS_OFFSET}(sp)",
                    "csrr a1, sepc",
                    "sd a1, {RET_PC_OFFSET}(sp)",
                    // 5. 保存用户栈的 sp
                    "csrr a2, sscratch",
                    "sd a2, {REGS_OFFSET}+8(sp)",
                    // 6. 将 stvec 改为内核态的版本
                    "la t0, trap_handler_raw_from_kernel",
                    "csrw stvec, t0",
                    // 7. 恢复 tp
                    "call {recover_task_pointer}",
                    // 8. 调用 trap_handler
                    "mv a0, sp", // 传参
                    "call trap_handler",
                    // 9. 返回用户态（U 特权级）
                    "j return_to_user", // 尾调用，无条件跳转即可
                    TRAP_CONTEXT_SIZE = const TRAP_CONTEXT_SIZE,
                    REGS_OFFSET = const REGS_OFFSET,
                    STATUS_OFFSET = const STATUS_OFFSET,
                    RET_PC_OFFSET = const RET_PC_OFFSET,
                    recover_task_pointer = sym recover_task_pointer,
                );
            });
        }
    }
    #[naked]
    #[unsafe(no_mangle)]
    extern "C" fn return_to_user() {
        unsafe {
            seq!(N in 3..=31 {
                naked_asm!(
                    // 1. 将 stvec 改为用户态的版本
                    "la t0, trap_handler_raw_from_user",
                    "csrw stvec, t0",
                    // 2. 恢复用户栈的 sp（到 sscratch 中）
                    "ld a2, {REGS_OFFSET}+8(sp)",
                    "csrw sscratch, a2",
                    // 3. 恢复 sepc 和 sstatus
                    "ld a1, {RET_PC_OFFSET}(sp)",
                    "csrw sepc, a1",
                    "ld a0, {STATUS_OFFSET}(sp)",
                    "csrw sstatus, a0",
                    // 4. 恢复先前保存的其它寄存器
                    "ld x1, {REGS_OFFSET}(sp)",
                    #(
                        concat!("ld x", N, ", (", N, "-1)*8+{REGS_OFFSET}(sp)"),
                    )*
                    // 5. 释放栈空间
                    "addi sp, sp, {TRAP_CONTEXT_SIZE}",
                    // 6. 切换回用户栈
                    "csrrw sp, sscratch, sp",
                    // 7. 返回用户态（U 特权级）
                    "sret",
                    TRAP_CONTEXT_SIZE = const TRAP_CONTEXT_SIZE,
                    REGS_OFFSET = const REGS_OFFSET,
                    STATUS_OFFSET = const STATUS_OFFSET,
                    RET_PC_OFFSET = const RET_PC_OFFSET,
                );
            });
        }
    }

    #[repr(align(4))]
    #[naked]
    #[unsafe(no_mangle)]
    extern "C" fn trap_handler_raw_from_kernel() {
        unsafe {
            seq!(N in 3..=31 {
                naked_asm!(
                    // 1. 为 TrapContext 留出栈空间
                    "addi sp, sp, -{TRAP_CONTEXT_SIZE}",
                    // 2. 保存寄存器（x1 ~ x31，不含 x2 (sp)——我们直接在原内核栈上操作，类似于直接函数调用）
                    "sd x1, {REGS_OFFSET}(sp)",
                    #(
                        concat!("sd x", N, ", (", N, "-1)*8+{REGS_OFFSET}(sp)"),
                    )*
                    // 3. 保存 sstatus 和 sepc
                    "csrr a0, sstatus",
                    "sd a0, {STATUS_OFFSET}(sp)",
                    "csrr a1, sepc",
                    "sd a1, {RET_PC_OFFSET}(sp)",
                    // 4. 调用 trap_handler
                    "mv a0, sp", // 传参
                    "call trap_handler",
                    // 5. 恢复 sepc 和 sstatus
                    "ld a1, {RET_PC_OFFSET}(sp)",
                    "csrw sepc, a1",
                    "ld a0, {STATUS_OFFSET}(sp)",
                    "csrw sstatus, a0",
                    // 6. 恢复先前保存的其它寄存器
                    "ld x1, {REGS_OFFSET}(sp)",
                    #(
                        concat!("ld x", N, ", (", N, "-1)*8+{REGS_OFFSET}(sp)"),
                    )*
                    // 7. 释放栈空间
                    "addi sp, sp, {TRAP_CONTEXT_SIZE}",
                    // 8. 返回，特权级保持不变
                    "sret",
                    TRAP_CONTEXT_SIZE = const TRAP_CONTEXT_SIZE,
                    REGS_OFFSET = const REGS_OFFSET,
                    STATUS_OFFSET = const STATUS_OFFSET,
                    RET_PC_OFFSET = const RET_PC_OFFSET,
                );
            });
        }
    }

    fn get_bad_address() -> usize {
        let stval: usize;
        unsafe {
            asm!(
                "csrr {0}, stval",
                out(reg) stval,
                options(nostack, nomem, preserves_flags),
            );
        }
        stval
    }

    fn set_global_interrupts_enable(enable: bool) {
        if enable {
            unsafe { riscv::register::sstatus::set_sie() }
        } else {
            unsafe { riscv::register::sstatus::clear_sie() }
        }
    }

    fn enable_timer_interrupt() {
        unsafe { riscv::register::sie::set_stimer() };
    }
}

#[repr(align(16))] // 上下文须压栈，RISC-V 64 要求栈按 16 字节对齐
#[derive(Clone, Copy)]
pub struct TrapContext {
    pub regs: Registers,
    pub status: usize,
    pub ret_pc: usize,
}

const TRAP_CONTEXT_SIZE: usize = size_of::<TrapContext>();
const REGS_OFFSET: usize = offset_of!(TrapContext, regs);
const STATUS_OFFSET: usize = offset_of!(TrapContext, status);
const RET_PC_OFFSET: usize = offset_of!(TrapContext, ret_pc);

macro_rules! regs {
    ($($name:ident),+ $(,)?) => {
        #[repr(C)]
        #[derive(Debug, Clone, Copy)]
        pub struct Registers {
            $(
                #[debug("{:#018x}", $name)]
                pub $name: usize,
            )+
        }
    };
}

regs!(
    ra, sp, gp, tp, t0, t1, t2, fp, s1, a0, a1, a2, a3, a4, a5, a6, a7, s2, s3, s4, s5, s6, s7, s8,
    s9, s10, s11, t3, t4, t5, t6
);

impl interfaces::TrapContext for TrapContext {
    type MContext = MContext;

    fn syscall_id(&self) -> usize {
        self.regs.a7
    }

    fn syscall_args(&self) -> &[usize; 6] {
        let ptr: *const usize = &self.regs.a0;
        unsafe { ptr.cast::<[usize; 6]>().as_ref_unchecked() }
    }

    fn ret_reg(&self) -> usize {
        self.regs.a0
    }

    fn ret_reg_mut(&mut self) -> &mut usize {
        &mut self.regs.a0
    }

    fn is_trap_from_kernel(&self) -> bool {
        self.status.get_bit(8)
    }

    fn get_mcontext(&self) -> Self::MContext {
        let mut gregs = [0usize; 32];
        *gregs[1..].as_mut_array::<31>().unwrap() = unsafe { transmute(self.regs) };
        gregs[0] = self.ret_pc;

        MContext {
            gregs,
            fpregs: [0; 66],
        }
    }
    fn with_mcontext(&mut self, mcontext: &Self::MContext) {
        self.ret_pc = mcontext.gregs[0];
        self.regs = unsafe { transmute(*mcontext.gregs[1..].as_array::<31>().unwrap()) };
    }
}

