pub struct AddressSpace {
    /// VMA 列表，不重叠、无零大小段且升序排列
    ///
    /// （为什么这里用 vector？因为我们根本不会有那么多 VMA 插入/删除，论内存占用、查找速度和实现简单性，有序数组甩其它数据结构十条街）
