        }

        if let Some(upper_bound) = self.vmas.get_mut(upper_bound)
            && upper_bound.start == vma.end
            && upper_bound.is_compatible_with(&vma)
        {
            // 与后一个 VMA 相邻，合并
            upper_bound.start = vma.start;
            return;
        }

        // 与前后 VMA 都不相邻，直接插入
        self.vmas.insert(upper_bound, vma);
    }

