#[derive(Clone, Copy)]
#[repr(transparent)]
pub struct SyscallFn {
    ptr: NonNull<()>,
}

// SAFETY: 外部无法构造 SyscallFn，只能访问 TABLE，它是只读的，也没有内部可变性
unsafe impl Sync for SyscallFn {}

impl SyscallFn {
    pub fn call(&self, args: &[usize; 6]) -> isize {
        let func_addr = self.ptr.as_ptr() as usize;

        let ret: isize;

        unsafe {
            #[cfg(target_arch = "riscv64")]
            asm!(
                "jalr ra, {func}",
                func = in(reg) func_addr,
                in("a0") args[0],
                in("a1") args[1],
                in("a2") args[2],
                in("a3") args[3],
                in("a4") args[4],
                in("a5") args[5],
                lateout("a0") ret,
                clobber_abi("C"),
            );
            #[cfg(target_arch = "loongarch64")]
            asm!(
                "jirl $ra, {func}, 0",
                func = in(reg) func_addr,
                in("$a0") args[0],
                in("$a1") args[1],
                in("$a2") args[2],
                in("$a3") args[3],
                in("$a4") args[4],
                in("$a5") args[5],
                lateout("$a0") ret,
                clobber_abi("C"),
            );
        }

        ret
    }

    pub fn addr(&self) -> usize {
        self.ptr.as_ptr().addr()
    }
}

