impl CloneFlags {
    pub fn check_validity(&self) -> SyscallResult {
        let bad = (self.contains(CloneFlags::THREAD) && !self.contains(CloneFlags::SIGHAND))
            || (self.contains(CloneFlags::SIGHAND) && !self.contains(CloneFlags::VM));

        if bad {
            EINVAL
        } else {
            SyscallResult::success(0)
        }
    }
}

