        let pipe = get_pipe(self);

        let base = if pipe.reader_count.load(Ordering::Acquire) == 0 {
            vfs::PollStatus::POLLERR
        } else {
            vfs::PollStatus::empty()
        };
        Ok(base | poll_impl(&*pipe.buffer.lock()))
