pub const USER_REGULAR_MEMORY_END: usize =
    (VIRTUAL_ADDRESS_LOW_HIGHEST + 1) - RESERVED_USER_VIRT_ADDR;
pub const USER_RESERVED_MEMORY_START: usize = USER_REGULAR_MEMORY_END;

pub const MMAP_START: VirtAddr = VirtAddr(0x8_0000_0000);
pub const MMAP_END: VirtAddr = VirtAddr(0x10_0000_0000);

pub const DYNAMIC_INTERPRETER_BASE: VirtAddr = VirtAddr(0x12_0000_0000);

pub const VIRTUAL_ADDRESS_HIGH_BASE: usize = if RISC_V {
    0xffff_ffc0_0000_0000
} else {
    0x1000_0000_0000_0000 // 此值要改就要连着 ld 脚本一起改
};
pub const LINEAR_MAPPING_OFFSET: usize = VIRTUAL_ADDRESS_HIGH_BASE;

impl PhysAddr {
    pub const fn to_virtual_address(&self) -> VirtAddr {
        VirtAddr(LINEAR_MAPPING_OFFSET + self.0)
    }
}
impl VirtAddr {
    pub const fn to_physical_address(&self) -> PhysAddr {
        PhysAddr(self.0 - LINEAR_MAPPING_OFFSET)
    }
}

impl VirtAddr {
    pub fn from_ptr<T>(ptr: *const T) -> Self {
        Self(ptr as usize)
    }

    pub fn as_ptr<T>(&self) -> *const T {
        self.0 as *const T
    }
    pub fn as_mut_ptr<T>(&self) -> *mut T {
        self.0 as *mut T
    }

    pub const fn floor_to_page(&self) -> Self {
        Self(self.0 / PAGE_BYTES * PAGE_BYTES)
    }
    pub const fn ceil_to_page(&self) -> Self {
        Self((self.0 + PAGE_BYTES - 1) / PAGE_BYTES * PAGE_BYTES)
    }
}

use bitflags::bitflags;

use crate::memory::address::PhysPageNum;

#[derive(Debug, Copy, Clone)]
#[repr(C)]
pub struct PageTableEntry<const LEVEL: usize> {
    pub bits: usize,
}

impl<const LEVEL: usize> PageTableEntry<LEVEL> {
    pub fn new(ppn: PhysPageNum<LEVEL>, flags: PTEFlags) -> Self {
        let flags: PTEFlagsNative = flags.into();
        Self {
            bits: ppn.mask() | flags.bits(),
        }
    }

    pub fn new_secondary_table(ppn: PhysPageNum<0>, flags: PTEFlags) -> Self {
        let flags: PTEFlagsNative = flags.into();
        Self {
            bits: ppn.mask() | flags.bits(),
        }
    }

    pub const fn new_invalid() -> Self {
        static_assertions::const_assert!(!PTEFlagsNative::Valid.is_empty());
        Self { bits: 0 }
    }

    pub fn flags(&self) -> PTEFlags {
        // bits 原本是使用按位或设定的，因此这里直接转换就能提取出 flags
        let flags_native = PTEFlagsNative::from_bits_truncate(self.bits);
        flags_native.into()
    }
}

#[cfg(target_arch = "riscv64")]
bitflags! {
    #[derive(Debug, Clone, Copy)]
    pub struct PTEFlagsNative: usize {
        const Valid = 1 << 0;
        const Read = 1 << 1;
        const Write = 1 << 2;
        const Execute = 1 << 3;
        const User = 1 << 4;
        const Global = 1 << 5;
        const Accessed = 1 << 6;
        const Dirty = 1 << 7;
    }
}

#[cfg(target_arch = "riscv64")]
pub type PTEFlags = PTEFlagsNative;

#[cfg(target_arch = "loongarch64")]
bitflags! {
    #[derive(Debug, Clone, Copy)]
    pub struct PTEFlagsNative: usize {
        const Valid = 1 << 0;
        const Dirty = 1 << 1;
        const User = 0b11 << 2;
        const Global = 1 << 6;

        const NRead = 1 << (usize::BITS - 3);
        const NExecute = 1 << (usize::BITS - 2);
    }

    #[derive(Debug, Clone, Copy)]
    pub struct PTEFlags: usize {
        const Valid = 1 << 0;
        const Dirty = 1 << 1;
        const User = 0b11 << 2;
        const Global = 1 << 6;

        const Read = 1 << (usize::BITS - 3);
        const Execute = 1 << (usize::BITS - 2);
        const Write = PTEFlags::Dirty.bits(); // LoongArch 64 没有单独的 Write 位，但可以用 Dirty 位在语义上替代
    }
}

#[cfg(target_arch = "loongarch64")]
impl From<PTEFlagsNative> for PTEFlags {
    fn from(value: PTEFlagsNative) -> Self {
        const MASK: usize = PTEFlagsNative::NRead.bits() | PTEFlagsNative::NExecute.bits();
        Self::from_bits_retain(value.bits() ^ MASK)
    }
}

#[cfg(target_arch = "loongarch64")]
impl From<PTEFlags> for PTEFlagsNative {
    fn from(value: PTEFlags) -> Self {
        const MASK: usize = PTEFlagsNative::NRead.bits() | PTEFlagsNative::NExecute.bits();
        Self::from_bits_retain(value.bits() ^ MASK)
    }
}

