#[derive(Debug, Default)]
pub struct RwLock<T: ?Sized> {
    state: AtomicU32,
    value: UnsafeCell<T>,
}

impl<T> RwLock<T> {
    pub const fn new(value: T) -> Self {
        Self {
            state: AtomicU32::new(0),
            value: UnsafeCell::new(value),
        }
    }

    pub const fn from_value(val: NonNull<T>) -> NonNull<Self> {
        unsafe { val.byte_sub(offset_of!(Self, value)).cast() }
    }

    pub fn into_inner(self) -> T {
        self.value.into_inner()
    }
}

impl<T: ?Sized> RwLock<T> {
    const WRITER_BIT: u32 = 1 << 31;

    #[track_caller]
    pub fn read(&self) -> RwLockReadGuard<'_, T> {
        loop {
            if let Some(guard) = self.try_read() {
                break guard;
            }

            panic!("我们现在还不支持并行，因此一定是发生了死锁");
            hint::spin_loop();
        }
    }

    #[track_caller]
    pub fn try_read(&self) -> Option<RwLockReadGuard<'_, T>> {
        self.state
            .fetch_update(Ordering::Acquire, Ordering::Relaxed, |state| {
                if state != Self::WRITER_BIT {
                    Some(state + 1)
                } else {
                    None
                }
            })
            .ok()
            .map(|_| RwLockReadGuard {
                value: unsafe { NonNull::new_unchecked(self.value.get()) },
                state: &self.state,
            })
    }

    #[track_caller]
    pub fn write(&self) -> RwLockWriteGuard<'_, T> {
        while self
            .state
            .compare_exchange_weak(0, Self::WRITER_BIT, Ordering::Acquire, Ordering::Relaxed)
            .is_err()
        {
            panic!("我们现在还不支持并行，因此一定是发生了死锁");
            hint::spin_loop();
        }

        RwLockWriteGuard {
            value: unsafe { NonNull::new_unchecked(self.value.get()) },
            state: &self.state,
        }
    }

    pub fn as_ptr(&self) -> *mut T {
        self.value.get()
    }

    pub fn get_mut(&mut self) -> &mut T {
        self.value.get_mut()
    }
}

pub struct RwLockReadGuard<'a, T: ?Sized> {
    value: NonNull<T>,
    state: &'a AtomicU32,
}
pub struct RwLockWriteGuard<'a, T: ?Sized> {
    value: NonNull<T>,
    state: &'a AtomicU32,
}

impl<T: ?Sized> Drop for RwLockReadGuard<'_, T> {
    fn drop(&mut self) {
        self.state.fetch_sub(1, Ordering::Release);
    }
}
impl<T: ?Sized> Drop for RwLockWriteGuard<'_, T> {
    fn drop(&mut self) {
        self.state.store(0, Ordering::Release);
    }
}

impl<T: ?Sized> Deref for RwLockReadGuard<'_, T> {
    type Target = T;

    #[inline(always)]
    fn deref(&self) -> &Self::Target {
        unsafe { self.value.as_ref() }
    }
}
impl<T: ?Sized> Deref for RwLockWriteGuard<'_, T> {
    type Target = T;

    #[inline(always)]
    fn deref(&self) -> &Self::Target {
        unsafe { self.value.as_ref() }
    }
}
impl<T: ?Sized> DerefMut for RwLockWriteGuard<'_, T> {
    #[inline(always)]
    fn deref_mut(&mut self) -> &mut Self::Target {
        unsafe { self.value.as_mut() }
    }
}

unsafe impl<T: ?Sized> DerefPure for RwLockReadGuard<'_, T> {}
unsafe impl<T: ?Sized> DerefPure for RwLockWriteGuard<'_, T> {}

struct TemporaryReleaseGuard<'a, T> {
    rwlock: &'a RwLock<T>,
}

impl<T> Drop for TemporaryReleaseGuard<'_, T> {
    fn drop(&mut self) {
        forget(self.rwlock.write());
    }
}

impl<T> RwLockWriteGuard<'_, T> {
    /// 临时释放锁。
    ///
    /// 其返回的 RAII 守卫会在析构时重新获取锁
    #[must_use]
    pub fn temporary_release(&mut self) -> impl Drop + '_ {
        self.state.store(0, Ordering::Release);
        TemporaryReleaseGuard {
            rwlock: unsafe { RwLock::from_value(self.value).as_ref() },
        }
    }
}

impl<'a, T: ?Sized> RwLockWriteGuard<'a, T> {
    #[must_use]
    pub fn downgrade(self) -> RwLockReadGuard<'a, T> {
        let this = ManuallyDrop::new(self);
        this.state.store(1, Ordering::Release);
        RwLockReadGuard {
            value: this.value,
            state: this.state,
        }
    }
}

unsafe impl<T: ?Sized + Send + Sync> Sync for RwLock<T> {}
unsafe impl<T: ?Sized + Send> Send for RwLock<T> {}

#[derive(Default)]
pub struct Mutex<T: ?Sized> {
    flag: AtomicBool,
    #[cfg(debug_assertions)]
    task: AtomicUsize,
    value: UnsafeCell<T>,
}

impl<T> Mutex<T> {
    pub const fn new(value: T) -> Self {
        Self {
            flag: AtomicBool::new(false),
            value: UnsafeCell::new(value),
            #[cfg(debug_assertions)]
            task: AtomicUsize::new(usize::MAX),
        }
    }

    pub const fn from_value(val: NonNull<T>) -> NonNull<Self> {
        unsafe { val.byte_sub(offset_of!(Self, value)).cast() }
    }

    pub const fn to_value(this: NonNull<Self>) -> NonNull<T> {
        unsafe { this.byte_add(offset_of!(Self, value)).cast() }
    }
}

impl<T: ?Sized> Mutex<T> {
    #[track_caller]
    pub fn lock(&self) -> MutexGuard<'_, T> {
        let guard = loop {
            if let Some(guard) = self.try_lock() {
                break guard;
            }

            // 注意我们暂时不支持并行，因此没有必要自旋（也没有必要区分自旋锁/睡眠锁），直接切换任务即可
            log::trace!(
                "Mutex {self:p} 被锁住了，尝试切换到其它任务（警告：这可能是死锁的征兆！）"
            );
            #[cfg(debug_assertions)]
            assert!(
                unsafe { current_task().as_ref() }
                    .is_none_or(|task| task.tid != self.task.load(Ordering::Relaxed)),
                "死锁了！TID = {}",
                self.task.load(Ordering::Relaxed)
            );
            syscall::basic::yield_();
        };

        #[cfg(debug_assertions)]
        unsafe { current_task().as_ref() }
            .inspect(|task| self.task.store(task.tid, Ordering::Relaxed));

        guard
    }

    pub fn get_mut(&mut self) -> &mut T {
        self.value.get_mut()
    }

    pub fn try_lock(&self) -> Option<MutexGuard<'_, T>> {
        if self.flag.swap(true, Ordering::Acquire) {
            None
        } else {
            Some(MutexGuard {
                value: unsafe { NonNull::new_unchecked(self.value.get()) },
                flag: &self.flag,
                #[cfg(debug_assertions)]
                task: &self.task,
            })
        }
    }

    pub fn as_ptr(&self) -> *mut T {
        self.value.get()
    }

    /// 假设锁已通过某种方式被释放，只是出于某种原因 [`MutexGuard`] 的析构函数暂时没有被执行（例如，如果 [`forget`][`core::mem::forget`] 了 guard，就会产生这种情况）
    ///
    /// 注意它不是解锁函数，也不执行任何内存同步。
    ///
    /// # Safety
    /// 在下一个 [`Self::lock`] 调用发生之后，原有的锁守卫（如果有）必须不再能被以任何方式使用（包括 drop，不包含移动）。
    ///
    /// 除此之外的操作都是安全的。例如，可以在未上锁的 [`Mutex`] 上调用此函数，且调用此函数后仍然可以使用原锁守卫。
    pub unsafe fn assume_unlocked(&self) {
        self.flag.store(false, Ordering::Relaxed);
    }
}

pub struct MutexGuard<'a, T: ?Sized> {
    value: NonNull<T>,
    flag: &'a AtomicBool,
    #[cfg(debug_assertions)]
    task: &'a AtomicUsize,
}

impl<T: ?Sized> Drop for MutexGuard<'_, T> {
    fn drop(&mut self) {
        self.flag.store(false, Ordering::Release);
        #[cfg(debug_assertions)]
        self.task.store(usize::MAX, Ordering::Relaxed);
    }
}

impl<T: ?Sized> Deref for MutexGuard<'_, T> {
    type Target = T;

    #[inline(always)]
    fn deref(&self) -> &Self::Target {
        unsafe { self.value.as_ref() }
    }
}

impl<T: ?Sized> DerefMut for MutexGuard<'_, T> {
    #[inline(always)]
    fn deref_mut(&mut self) -> &mut Self::Target {
        unsafe { self.value.as_mut() }
    }
}

